.darma-loader-darma-custom-770 {
  color: var(--loader-color, #6366f1);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
width: 32px;
aspect-ratio: 1;
--_g: no-repeat radial-gradient(farthest-side,currentColor 90%,#0000);
background: var(--_g), var(--_g), var(--_g), var(--_g);
background-size: 40% 40%;
animation: darma-loader-darma-custom-770-l46 1s infinite;
}
@keyframes darma-loader-darma-custom-770-l46 {
0% {background-position: 0 0 ,100% 0,100% 100%,0 100%}
40%,
50% {background-position: 100% 100%,100% 0,0 0 ,0 100%}
90%,
100%{background-position: 100% 100%,0 100%,0 0 ,100% 0}
}

